import*as fs from"fs";import*as path from"path";import{exec}from"child_process";import{package_info,locale_dir,source_dir}from"#root/_package.js";const entries=fs.readdirSync(locale_dir,{withFileTypes:!0}),package_langs=entries.filter(o=>o.isDirectory()).map(o=>o.name);package_langs.forEach(o=>{const e=path.join(locale_dir,o,"LC_MESSAGES",`${package_info.name}.po`);if(fs.existsSync(e)){const r=path.join(locale_dir,o,"LC_MESSAGES",`${package_info.name}.mo`);exec(`      msgfmt -vv -o ${r} ${e}\n    `,(o,a,i)=>{o?console.error(`Error generating "${r}" from "${e}"`):console.log(`Generating ${r} from "${e}" .`)})}});